import React from 'react';

const logos = [
    { alt: "Vercel", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/vercel.svg" },
    { alt: "GitHub", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/github.svg" },
    { alt: "GitLab", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/gitlab.svg" },
    { alt: "Google Cloud", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/googlecloud.svg" },
    { alt: "JetBrains", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/jetbrains.svg" },
    { alt: "Netlify", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/netlify.svg" },
    { alt: "DigitalOcean", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/digitalocean.svg" },
    { alt: "Cloudflare", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/cloudflare.svg" },
    { alt: "Stripe", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/stripe.svg" },
    { alt: "Docker", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/docker.svg" },
    { alt: "Kubernetes", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/kubernetes.svg" },
    { alt: "PostgreSQL", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/postgresql.svg" },
    { alt: "MongoDB", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/mongodb.svg" },
    { alt: "Sentry", src: "https://cdn.jsdelivr.net/npm/simple-icons@v11/icons/sentry.svg" },
];

const Row = ({ reverse = false }) => {
    return (
        <div className="relative overflow-hidden py-4 group">
            <div
                className={`flex items-center gap-10 min-w-max will-change-transform ${reverse ? "animate-marquee-reverse" : "animate-marquee"
                    } group-hover:[animation-play-state:paused]`}
            >
                {[...logos, ...logos].map((logo, idx) => (
                    <img
                        key={`${logo.alt}-${idx}`}
                        src={logo.src}
                        alt={logo.alt}
                        className="h-8 w-auto opacity-70 hover:opacity-100 transition-opacity grayscale hover:grayscale-0 dark:invert dark:brightness-200"
                        loading="lazy"
                    />
                ))}
            </div>
        </div>
    );
};

const LogoMarquee = () => {
    return (
        <section aria-label="Trusted by" className="py-10 relative bg-background/50 border-y border-border/40 backdrop-blur-sm">
            <div className="max-w-7xl mx-auto px-6 sm:px-8 lg:px-12">
                <div className="text-center mb-6">
                    <p className="text-sm font-medium uppercase tracking-widest text-muted-foreground/80">
                        Trusted by top engineering teams
                    </p>
                </div>
                <div className="relative">
                    <Row />
                    <div className="absolute inset-y-0 left-0 w-24 bg-gradient-to-r from-background to-transparent z-10 pointer-events-none" />
                    <div className="absolute inset-y-0 right-0 w-24 bg-gradient-to-l from-background to-transparent z-10 pointer-events-none" />
                </div>
                <div className="relative mt-2">
                    <Row reverse />
                    <div className="absolute inset-y-0 left-0 w-24 bg-gradient-to-r from-background to-transparent z-10 pointer-events-none" />
                    <div className="absolute inset-y-0 right-0 w-24 bg-gradient-to-l from-background to-transparent z-10 pointer-events-none" />
                </div>
            </div>
        </section>
    );
};

export default LogoMarquee;
